class SudokuSolver:
    def __init__(self, board):
        self.board = board
        self.N = 9

    def _find_empty(self):
        for r in range(self.N):
            for c in range(self.N):
                if self.board[r][c] == 0:
                    return (r, c)
        return None

    def _is_valid(self, num, pos):
        row, col = pos

        for c in range(self.N):
            if self.board[row][c] == num:
                return False

        for r in range(self.N):
            if self.board[r][col] == num:
                return False

        box_start_row = (row // 3) * 3
        box_start_col = (col // 3) * 3

        for r_box in range(box_start_row, box_start_row + 3):
            for c_box in range(box_start_col, box_start_col + 3):
                if self.board[r_box][c_box] == num:
                    return False
        return True

    def solve(self):
        find = self._find_empty()
        if not find:
            return True

        row, col = find

        for num in range(1, 10):
            if self._is_valid(num, (row, col)):
                self.board[row][col] = num

                if self.solve():
                    return True

                self.board[row][col] = 0

        return False

    def print_board(self):
        for r in range(self.N):
            if r % 3 == 0 and r != 0:
                print("- - - - - - - - - - - - ")

            for c in range(self.N):
                if c % 3 == 0 and c != 0:
                    print(" | ", end="")

                if c == 8:
                    print(self.board[r][c])
                else:
                    print(str(self.board[r][c]) + " ", end="")


